root.1/canonical_standard.json:
{
  "metadata": {
    "version": "1.0.0",
    "source": "Cheonma Legacy Codebase Analysis (v2.4 - v3.1)",
    "description": "Canonical terminology standard for Cheonma Payments Platform"
  },
  "casing_rules": {
    "endpoint_nouns": "kebab-case",
    "error_codes": "SCREAMING_SNAKE_CASE",
    "json_keys": "camelCase",
    "environment_variables": "SCREAMING_SNAKE_CASE",
    "class_names": "PascalCase"
  },
  "endpoint_nouns": {
    "description": "Allowed nouns for API resource endpoints. Must be pluralized.",
    "allowed": [
      "payments",
      "refunds",
      "merchants",
      "accounts",
      "transactions",
      "settlements",
      "disputes",
      "webhooks"
    ],
    "forbidden": [
      "payment",
      "refund",
      "merchant",
      "account",
      "transaction",
      "settlement",
      "dispute",
      "webhook",
      "orders",
      "invoices"
    ]
  },
  "error_codes": {
    "description": "Standardized error codes for Cheonma API responses.",
    "definitions": [
      {
        "code": "INVALID_REQUEST",
        "http_status": 400,
        "description": "Malformed request body or missing required fields."
      },
      {
        "code": "AUTHENTICATION_FAILED",
        "http_status": 401,
        "description": "Invalid or missing API key."
      },
      {
        "code": "INSUFFICIENT_PERMISSIONS",
        "http_status": 403,
        "description": "API key lacks scope for requested action."
      },
      {
        "code": "RESOURCE_NOT_FOUND",
        "http_status": 404,
        "description": "Requested resource ID does not exist."
      },
      {
        "code": "CONFLICT",
        "http_status": 409,
        "description": "State conflict, e.g., refunding an already refunded payment."
      },
      {
        "code": "RATE_LIMIT_EXCEEDED",
        "http_status": 429,
        "description": "Too many requests."
      },
      {
        "code": "INTERNAL_ERROR",
        "http_status": 500,
        "description": "Unexpected server error."
      },
      {
        "code": "SERVICE_UNAVAILABLE",
        "http_status": 503,
        "description": "Downstream dependency failure."
      },
      {
        "code": "PAYMENT_DECLINED",
        "http_status": 402,
        "description": "Payment processor declined the transaction."
      },
      {
        "code": "REFUND_LIMIT_EXCEEDED",
        "http_status": 400,
        "description": "Refund amount exceeds original payment amount."
      }
    ]
  },
  "naming_conventions": {
    "endpoint_structure": "/v{version}/{resource_noun}/{id?}",
    "example_endpoint": "/v1/payments/{payment_id}",
    "error_response_format": {
      "error": {
        "code": "<SCREAMING_SNAKE_CASE>",
        "message": "<Human-readable description>",
        "details": "<Optional context>"
      }
    }
  }
}
